INSERT INTO `tb_media_hafalan` (`id`, `nama_media`, `jenis_media`, `url_link`, `deskripsi`, `tips_belajar`, `alasan_rekomendasi`, `is_active`, `tanggal_input`, `created_at`, `updated_at`) VALUES
(1, 'Mushaf Tajwid Warna', 'cetak', NULL, 'Mushaf Al-Qur\'an dengan penanda tajwid berwarna untuk memudahkan pemula.', 'Baca 1 halaman per hari dengan memperhatikan warna tajwid. Ulangi bacaan yang sulit dua kali.', 'Cocok untuk siswa yang masih perlu perbaikan dasar tajwid dan makhraj.', 1, '2026-05-15 07:32:16', NULL, NULL),
(2, 'Buku Panduan Makhraj Huruf', 'cetak', NULL, 'Panduan lengkap makhraj 28 huruf hijaiyah disertai ilustrasi posisi lidah.', 'Fokus pada huruf ح خ ع غ yang sering salah. Latih di depan cermin setiap hari.', 'Membantu siswa menyempurnakan makhraj huruf.', 1, '2026-05-15 07:32:16', NULL, NULL),
(3, 'Juz Amma Terjemah', 'cetak', NULL, 'Juz Amma dilengkapi terjemah, asbabun nuzul, dan panduan hafalan per surah.', 'Pahami makna setiap ayat sebelum menghafal. Ini akan memperkuat hafalan jangka panjang.', 'Untuk siswa berprestasi yang ingin memperdalam pemahaman makna hafalan.', 1, '2026-05-15 07:32:16', NULL, NULL),
(4, 'Video Tajwid Pemula (YouTube)', 'digital', 'https://www.youtube.com/watch?v=example1', 'Serial video pembelajaran tajwid dari dasar untuk pemula, total 20 episode.', 'Tonton sambil mengulang bacaan. Aktifkan subtitle untuk membantu pemahaman.', 'Media visual interaktif untuk siswa yang butuh bimbingan tajwid intensif.', 1, '2026-05-20 07:32:16', NULL, NULL),
(5, 'Aplikasi Hafalan Qur\'an (Web)', 'digital', 'https://quran.com', 'Platform web Quran.com dengan fitur audio, terjemah, dan mode hafalan.', 'Gunakan fitur repeat ayat dan aktifkan mode Tafsir untuk pemahaman lebih dalam.', 'Mendukung latihan mandiri dengan umpan balik audio berkualitas tinggi.', 1, '2026-05-20 07:32:16', NULL, NULL),
(6, 'Audio Murottal Syaikh Sudais', 'digital', 'https://download.quranicaudio.com/example', 'Murottal lengkap 30 juz oleh Syaikh Abdurrahman As-Sudais dengan kualitas HD.', 'Dengarkan dan ikuti bacaan beliau. Perhatikan tempo dan nafas pada ayat panjang.', 'Referensi bacaan fasih level tinggi untuk siswa yang sudah menguasai dasar.', 1, '2026-05-20 07:32:16', NULL, NULL),
(7, 'Media Cetak', 'cetak', NULL, NULL, NULL, NULL, 1, '2026-07-15 16:52:46', NULL, NULL),
(8, 'Media Digital', 'cetak', NULL, NULL, NULL, NULL, 1, '2026-07-15 16:52:46', NULL, NULL),
(9, 'Media Aplikasi', 'cetak', NULL, NULL, NULL, NULL, 1, '2026-07-15 16:52:46', NULL, NULL);
